1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	const parseKey = (key: string): Cell => key.split(",").map(Number) as Cell;
5	
6	const survivesOrIsBorn = (isAlive: boolean, neighborCount: number): boolean =>
7	  neighborCount === 3 || (isAlive && neighborCount === 2);
8	
9	export function nextGeneration(cells: Cell[]): Cell[] {
10	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
11	  const neighborCounts = new Map<string, number>();
12	
13	  for (const [x, y] of cells) {
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const key = cellKey(x + dx, y + dy);
18	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const result: Cell[] = [];
24	  for (const [key, count] of neighborCounts) {
25	    if (survivesOrIsBorn(liveSet.has(key), count)) {
26	      result.push(parseKey(key));
27	    }
28	  }
29	
30	  return result;
31	}
